INSERT INTO projects (title,slug,stall_area_sqm,stall_area_sqft,stall_height_m,floors,build_year,city,exhibition_id,client_id,description,design_brief,ai_summary,design_style,materials_used,special_features,awards,status,is_featured,display_order) VALUES ('Securus 18 SQM 2 Side Open Stall Exhibition Stall Design at FITAG Tech Expo - IT Show, Gandhinagar 2025','securus-18-sqm-custom-exhibition-stall-fitag-tech-expo-it-show-gandhinagar-2025',18,193.75,4,1,2025,'Gandhinagar',(SELECT id FROM exhibitions WHERE slug='fitag-tech-expo-it-show' LIMIT 1),(SELECT id FROM clients WHERE slug='securus' LIMIT 1),'Approach Media designed and fabricated an 18 SQM 2 side open stall exhibition stall for Securus at FITAG Tech Expo - IT Show, Helipad Ground, Gandhinagar. The booth presents a security and surveillance stall with red-white fascia branding, camera and solution display panels, open visitor edges, and a compact product consultation layout. The stall was planned for strong brand recall, clear product visibility, easy visitor movement, and search-friendly portfolio discovery for security devises, it, hardware, television exhibition projects in Gandhinagar, India.','Create an 18 SQM 2 side open stall custom exhibition stall for Securus that communicates technology, product credibility, and visitor engagement at FITAG Tech Expo - IT Show. The design needed visible branding, product-led storytelling, practical discussion areas, and a premium finish suitable for a busy expo environment.','Securus exhibition stall by Approach Media at FITAG Tech Expo - IT Show, Gandhinagar: 18 SQM 2 side open stall booth with professional security solutions booth with strong red-white visual identity, designed for product display, lead generation, visitor interaction, and high search relevance around custom exhibition stall design and fabrication in Gujarat.','Professional security solutions booth with strong red-white visual identity','["Wooden exhibition structure", "laminate finish", "printed vinyl panels", "acrylic logo", "LED lighting", "carpet flooring"]','["Two-side open access", "security product display panels", "red-white fascia", "demo wall", "compact meeting and inquiry area"]',NULL,'published',true,50) ON CONFLICT (slug) DO NOTHING;
